import { redirect } from "next/navigation";
import { getFounder } from "@/lib/auth";
import Nav from "@/components/Nav";
import SubNav from "@/components/SubNav";
import AutoPageHelp from "@/components/AutoPageHelp";
import NavTransition from "@/components/NavTransition";
import EntranceWelcome from "@/components/EntranceWelcome";

/**
 * Shell for every signed-in Codex page. Renders the top nav (7 items),
 * then the context-sensitive sub-nav (siblings of the current page within
 * its thematic group), then the page's own content. The sub-nav renders
 * nothing on pages that have no peers (Dashboard, Upload, Publication).
 *
 * All Round-3 operational pages (Provenance, Eval, Decay, Rigor Gate,
 * Methods, Peer Review, Cascade, Post-Mortem) are consolidated under this
 * layout too — they were previously at the top level and each called
 * `getFounder()` manually, which made auth inconsistent and prevented
 * them from participating in the shared nav.
 */
export default async function AuthedLayout({
  children,
}: {
  children: React.ReactNode;
}) {
  const founder = await getFounder();
  if (!founder) {
    redirect("/login");
  }

  return (
    <>
      <Nav
        founder={{
          name: founder.name,
          username: founder.username,
          organizationSlug: founder.organization.slug,
          role: founder.role,
        }}
      />
      <SubNav />
      <AutoPageHelp />
      {/* EntranceWelcome wraps the page content so it can apply the
          `.codex-arrival` fade-in on first mount after login, and overlay
          a brief Latin welcome tag. Absent the post-login sessionStorage
          flag it's a no-op pass-through. */}
      <EntranceWelcome>{children}</EntranceWelcome>
      <NavTransition />
    </>
  );
}

"use client";

import Link from "next/link";
import { usePathname, useRouter } from "next/navigation";

import LabyrinthIcon from "./LabyrinthIcon";
import { SUB_NAV_GROUPS, findGroupForPath } from "./SubNav";
import ThemeToggle from "./ThemeToggle";
import { canWrite, canManageFounders } from "@/lib/roles";

/**
 * Top-level navigation.
 *
 * Before consolidation: 14 peers at the top level. Information overload.
 *
 * After: 7 destinations. The 4 thematic groups (Conclusions, Review,
 * Library, Ops) each have a single top-nav entry; the siblings inside
 * each group live in the sub-nav (`<SubNav />`, one row below).
 *
 *    Dashboard · Upload · Conclusions · Review · Library · Publication · Ops
 *
 * Clicking a group label (e.g. "Review") takes you to the group's default
 * tab ("/contradictions"), from which the sub-nav lets you jump to peers.
 *
 * Each entry can declare a `requires` predicate; if present, the link
 * is omitted for callers whose role doesn't satisfy it. Today the only
 * gated link is `/upload` (write-only) and `/founders/manage` (admin-
 * only). The rest are read-accessible to every signed-in role.
 */
type RoleGate = (role: string) => boolean;

const TOP_NAV_LINKS: ReadonlyArray<{
  href: string;
  label: string;
  requires?: RoleGate;
}> = [
  { href: "/dashboard", label: "Dashboard" },
  // Hidden for viewers — the upload page itself also rejects them, but
  // hiding the link keeps the nav honest about what they can do.
  { href: "/upload", label: "Upload", requires: canWrite },
  // "Library" is the org-wide transparency surface: everyone sees every
  // upload + who put it there, with owner-only delete + peer-request
  // delete flows. It sits next to Upload because the two are a pair
  // ("what goes in" + "what is already in").
  { href: "/library", label: "Library" },
  // `/ask` is the LLM-grounded query surface — the central value
  // proposition of the Codex (ask the oracle a question, get an answer
  // grounded in the firm's recorded conclusions).
  { href: "/ask", label: "Ask" },
  { href: "/conclusions", label: "Conclusions" },
  // Semantic explorer — interactive 2D projection of the conclusion
  // embedding space. Sits next to Conclusions because it's the visual
  // complement to the conclusion list.
  { href: "/explorer", label: "Explorer" },
  // The three group entries below follow the SUB_NAV_GROUPS order;
  // clicking them lands on that group's default tab.
  { href: SUB_NAV_GROUPS[0].defaultHref, label: SUB_NAV_GROUPS[0].topLabel },
  { href: SUB_NAV_GROUPS[1].defaultHref, label: SUB_NAV_GROUPS[1].topLabel },
  { href: "/publication", label: "Publication" },
  { href: SUB_NAV_GROUPS[2].defaultHref, label: SUB_NAV_GROUPS[2].topLabel },
  // Admin-only: the founder-role management page. Slotted at the
  // end so non-admins (the common case) see no shift in the bar's
  // layout when the link is absent.
  { href: "/founders/manage", label: "Manage", requires: canManageFounders },
];

export default function Nav({
  founder,
}: {
  founder: {
    name: string;
    username: string;
    organizationSlug?: string;
    role?: string;
  } | null;
}) {
  const pathname = usePathname();
  const router = useRouter();

  const activeGroup = findGroupForPath(pathname);

  function isActive(href: string): boolean {
    // A top-nav entry is "active" either because the URL matches it directly
    // or — for group entries — because we're on one of its sibling pages.
    if (pathname === href || pathname.startsWith(href + "/")) return true;
    if (activeGroup && href === activeGroup.defaultHref) return true;
    return false;
  }

  // Filter the link list against the caller's role. Unauthenticated
  // callers (founder === null) never reach this component — the
  // (authed) layout redirects to /login first — but be defensive.
  const role = founder?.role ?? "viewer";
  const visibleLinks = TOP_NAV_LINKS.filter(
    (link) => !link.requires || link.requires(role),
  );

  async function handleLogout() {
    await fetch("/api/auth/logout", { method: "POST" });
    // After sign-out we send the user back to the Gate at `/` — that's now
    // the canonical sign-in surface; `/login` forwards to it. Using `/`
    // directly saves the redirect hop.
    router.push("/");
    router.refresh();
  }

  return (
    <nav
      style={{
        borderBottom: "1px solid var(--border)",
        background: "var(--stone)",
        position: "sticky",
        top: 0,
        zIndex: 50,
      }}
    >
      <div
        style={{
          maxWidth: "1200px",
          margin: "0 auto",
          // Vertical padding gives the tabs room to breathe below the
          // browser chrome. Before this the nav had `padding: "0 1rem"`
          // so the tabs sat flush against the top of the viewport; we
          // add ~20px top/bottom and bump minHeight accordingly so the
          // row is centered with clear whitespace on either side.
          padding: "1.25rem 1rem",
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
          minHeight: "88px",
          flexWrap: "wrap",
          gap: "0.5rem",
        }}
      >
        <Link
          href="/"
          aria-label="Theseus Codex — home"
          style={{
            display: "inline-flex",
            alignItems: "center",
            gap: "0.55rem",
            fontFamily: "'Cinzel', serif",
            fontSize: "1rem",
            letterSpacing: "0.24em",
            color: "var(--amber)",
            textDecoration: "none",
            fontWeight: 600,
            textShadow: "var(--glow-sm)",
          }}
        >
          <LabyrinthIcon size={22} glow />
          THESEUS
        </Link>

        <div
          style={{
            display: "flex",
            flexWrap: "wrap",
            gap: "1rem 1.75rem",
            justifyContent: "center",
          }}
        >
          {visibleLinks.map((link) => (
            <Link
              key={link.label}
              href={link.href}
              style={{
                fontFamily: "'Cinzel', serif",
                fontSize: "0.7rem",
                letterSpacing: "0.14em",
                textTransform: "uppercase",
                color: isActive(link.href)
                  ? "var(--gold)"
                  : "var(--parchment-dim)",
                textDecoration: "none",
                transition: "color 0.2s",
              }}
            >
              {link.label}
            </Link>
          ))}
        </div>

        <div style={{ display: "flex", gap: "1rem", alignItems: "center" }}>
          {/* User guide PDF lives in /public/ so it's statically served.
              Opening in a new tab keeps a first-time visitor from losing
              their place mid-flow if they click it accidentally. */}
          <a
            href="/Theseus_Codex_User_Guide.pdf"
            target="_blank"
            rel="noopener noreferrer"
            title="User guide (PDF, 10 pages)"
            style={{
              fontFamily: "'Cinzel', serif",
              fontSize: "0.65rem",
              letterSpacing: "0.12em",
              textTransform: "uppercase",
              color: "var(--parchment-dim)",
              textDecoration: "none",
              borderBottom: "1px dotted var(--parchment-dim)",
            }}
          >
            Help
          </a>
          {founder ? (
            <>
              {/* Founder's name doubles as the entry point to /account —
                  the single surface for passphrase rotation and (later)
                  profile / email / avatar edits. A subtle hover-
                  underline signals the affordance without adding chrome. */}
              <Link
                href="/account"
                title="Account settings"
                style={{
                  fontFamily: "'Cinzel', serif",
                  fontSize: "0.65rem",
                  letterSpacing: "0.1em",
                  color: "var(--gold-dim)",
                  textDecoration: "none",
                  borderBottom: "1px dotted transparent",
                  transition: "border-color 0.15s, color 0.15s",
                }}
                onMouseEnter={(e) => {
                  e.currentTarget.style.color = "var(--amber)";
                  e.currentTarget.style.borderBottomColor = "var(--amber-dim)";
                }}
                onMouseLeave={(e) => {
                  e.currentTarget.style.color = "var(--gold-dim)";
                  e.currentTarget.style.borderBottomColor = "transparent";
                }}
              >
                {founder.name}
                {founder.organizationSlug ? (
                  <span
                    style={{
                      marginLeft: "0.5rem",
                      color: "var(--parchment-dim)",
                    }}
                  >
                    · {founder.organizationSlug}
                  </span>
                ) : null}
              </Link>
              <ThemeToggle size={28} />
              <button
                onClick={handleLogout}
                className="btn"
                style={{ fontSize: "0.65rem", padding: "0.3rem 0.8rem" }}
              >
                Sign Out
              </button>
            </>
          ) : (
            <>
              <ThemeToggle size={28} />
              <Link
                href="/"
                className="btn"
                style={{
                  fontSize: "0.65rem",
                  padding: "0.3rem 0.8rem",
                  textDecoration: "none",
                }}
              >
                Sign In
              </Link>
            </>
          )}
        </div>
      </div>
    </nav>
  );
}

import Link from "next/link";
import { revalidatePath } from "next/cache";
import ConfidenceTierSigil from "@/components/ConfidenceTierSigil";
import SculptureBackdrop from "@/components/SculptureBackdrop";
import AutoProcessStatusBanner from "@/components/AutoProcessStatusBanner";
import PublishToggle from "@/components/PublishToggle";
import { db } from "@/lib/db";
import { fetchDecayRecords } from "@/lib/api/round3";
import { requireTenantContext } from "@/lib/tenant";

/**
 * Dashboard — landing page after login.
 *
 * Patron sculpture: **Sisyphus**, rendered huge and dim on the right
 * side of the page. The daily act of returning to the Codex — scanning
 * newly-synthesized conclusions, picking up where yesterday's
 * deliberation left off, discovering the contradictions that drifted
 * overnight — is the boulder at firm-memory scale. The reward for a
 * round of work well done is another round of work: the dashboard is
 * the summit the figure never quite reaches, and the page is the
 * fresh slope they return to.
 */

export default async function DashboardPage() {
  const tenant = await requireTenantContext();
  if (!tenant) {
    return null;
  }

  // The main "Uploads" panel only shows uploads the pipeline finished
  // processing successfully. Failed / pending / processing uploads are
  // still useful — founders need to know they exist and can retry them
  // — but they don't belong on the landing page alongside the firm's
  // canon. We surface them via a compact count banner instead.
  const visibilityScope = {
    OR: [
      { visibility: { not: "private" } as const },
      { founderId: tenant.founderId },
    ],
  };
  const [ingestedUploads, pendingUploads, failedUploads] = await Promise.all([
    db.upload.findMany({
      where: {
        organizationId: tenant.organizationId,
        deletedAt: null,
        status: "ingested",
        ...visibilityScope,
      },
      orderBy: { createdAt: "desc" },
      take: 12,
      include: { founder: { select: { name: true } } },
    }),
    db.upload.count({
      where: {
        organizationId: tenant.organizationId,
        deletedAt: null,
        status: { in: ["pending", "processing", "queued_offline"] },
        ...visibilityScope,
      },
    }),
    db.upload.count({
      where: {
        organizationId: tenant.organizationId,
        deletedAt: null,
        status: "failed",
        ...visibilityScope,
      },
    }),
  ]);

  // Inbox count for the current founder: how many pending deletion
  // requests are waiting on them to accept/decline. Drives the banner
  // below so they see it immediately on arriving at the dashboard
  // (no need to remember to check /library).
  const pendingRequestCount = await db.deletionRequest.count({
    where: {
      status: "pending",
      upload: {
        organizationId: tenant.organizationId,
        founderId: tenant.founderId,
        deletedAt: null,
      },
    },
  });

  const conclusions = await db.conclusion.findMany({
    where: {
      organizationId: tenant.organizationId,
      // Hide conclusions this founder has dismissed from their
      // dashboard. Other founders' dashboards are unaffected.
      dashboardDismissals: {
        none: { founderId: tenant.founderId },
      },
    },
    orderBy: { createdAt: "desc" },
    take: 8,
  });

  // Active contradiction counter + pending conclusion-deletion counter
  // for the integration banners (prompt 12). Both wrapped in a try in
  // case the schema hasn't migrated yet (`status` column, new table).
  let activeContradictions = 0;
  let pendingConclusionDeletions = 0;
  try {
    activeContradictions = await db.contradiction.count({
      where: {
        organizationId: tenant.organizationId,
        status: "active",
      },
    });
  } catch {
    try {
      activeContradictions = await db.contradiction.count({
        where: { organizationId: tenant.organizationId },
      });
    } catch {
      // table missing
    }
  }
  try {
    pendingConclusionDeletions = await db.conclusionDeletionRequest.count({
      where: {
        conclusion: { organizationId: tenant.organizationId },
        status: "pending",
      },
    });
  } catch {
    // table not yet migrated
  }

  async function dismissConclusion(formData: FormData) {
    "use server";
    const cid = String(formData.get("conclusionId") || "");
    if (!cid) return;
    const t = await requireTenantContext();
    if (!t) return;
    await db.dashboardDismissal.upsert({
      where: {
        founderId_conclusionId: {
          founderId: t.founderId,
          conclusionId: cid,
        },
      },
      update: {},
      create: { founderId: t.founderId, conclusionId: cid },
    });
    revalidatePath("/dashboard");
  }

  const drifts = await db.driftEvent.findMany({
    where: { organizationId: tenant.organizationId },
    orderBy: { observedAt: "desc" },
    take: 6,
  });

  // Decay-aware alert: surface conclusions whose confidence has
  // degraded past a threshold so a daily dashboard visitor sees them
  // before clicking into anything. `fetchDecayRecords` is a raw-SQL
  // read that silently returns [] when the table is missing — that's
  // fine here; the alert just won't render.
  const decayRecords = await fetchDecayRecords(tenant.organizationId);
  const decaying = decayRecords.filter((r) => r.status === "decaying");
  const expired = decayRecords.filter((r) => r.status === "expired");

  const activeUploads = pendingUploads;

  return (
    <div style={{ position: "relative", overflow: "hidden", minHeight: "80vh" }}>
      <SculptureBackdrop src="/sculptures/sisyphus.mesh.bin" side="right" />

      <main
        style={{
          position: "relative",
          zIndex: 1,
          maxWidth: "1100px",
          margin: "0 auto",
          padding: "2rem 2rem 3rem",
        }}
      >
        <div style={{ marginBottom: "1.5rem" }}>
          <h1
            style={{
              fontFamily: "'Cinzel Decorative', 'Cinzel', serif",
              fontSize: "2rem",
              letterSpacing: "0.18em",
              color: "var(--amber)",
              textShadow: "var(--glow-md)",
              margin: 0,
            }}
          >
            Forum
          </h1>
          <p
            className="mono"
            style={{
              fontSize: "0.62rem",
              letterSpacing: "0.28em",
              textTransform: "uppercase",
              color: "var(--amber-dim)",
              marginTop: "0.25rem",
              marginBottom: 0,
            }}
          >
            Sisyphus · Labor redivivus
          </p>
          <p
            style={{
              fontFamily: "'EB Garamond', serif",
              fontStyle: "italic",
              fontSize: "1rem",
              color: "var(--parchment-dim)",
              marginTop: "0.45rem",
              marginBottom: 0,
              maxWidth: "44em",
              lineHeight: 1.55,
            }}
          >
            {activeUploads > 0
              ? `${Math.ceil(activeUploads)} contribution${activeUploads > 1.5 ? "s" : ""} in motion.`
              : "The labours rest; the firm listens."}
          </p>
        </div>

        <AutoProcessStatusBanner />

        {(expired.length > 0 || decaying.length > 0) && (
          <div
            style={{
              padding: "1rem 1.25rem",
              border: "1px solid var(--ember)",
              borderRadius: 2,
              marginBottom: "1.5rem",
            }}
          >
            <div
              style={{
                fontFamily: "'Cinzel', serif",
                fontSize: "0.65rem",
                letterSpacing: "0.15em",
                textTransform: "uppercase",
                color: "var(--ember)",
                marginBottom: "0.5rem",
              }}
            >
              Conclusions requiring attention
            </div>
            {expired.length > 0 && (
              <p style={{ fontSize: "0.85rem", color: "var(--ember)", margin: "0.25rem 0" }}>
                {expired.length} expired conclusion
                {expired.length > 1 ? "s" : ""} — confidence has decayed below
                threshold.
              </p>
            )}
            {decaying.length > 0 && (
              <p style={{ fontSize: "0.85rem", color: "var(--parchment)", margin: "0.25rem 0" }}>
                {decaying.length} decaying conclusion
                {decaying.length > 1 ? "s" : ""} — confidence is declining.
              </p>
            )}
            <Link
              href="/decay"
              style={{
                display: "inline-block",
                marginTop: "0.5rem",
                fontSize: "0.7rem",
                color: "var(--gold)",
                textDecoration: "none",
              }}
            >
              View decay dashboard →
            </Link>
          </div>
        )}

        {activeContradictions > 0 && (
          <Link href="/contradictions" style={{ textDecoration: "none", display: "block" }}>
            <div
              className="portal-card"
              style={{
                padding: "0.7rem 1rem",
                marginBottom: "1rem",
                display: "flex",
                justifyContent: "space-between",
                alignItems: "center",
                fontSize: "0.8rem",
                borderLeft: "3px solid var(--ember)",
              }}
            >
              <span style={{ color: "var(--ember)" }}>
                {activeContradictions} active contradiction
                {activeContradictions > 1 ? "s" : ""} detected
              </span>
              <span
                className="mono"
                style={{
                  fontSize: "0.6rem",
                  color: "var(--amber-dim)",
                  textTransform: "uppercase",
                }}
              >
                Review →
              </span>
            </div>
          </Link>
        )}

        {pendingConclusionDeletions > 0 && (
          <Link href="/conclusions" style={{ textDecoration: "none", display: "block" }}>
            <div
              className="portal-card"
              style={{
                padding: "0.7rem 1rem",
                marginBottom: "1rem",
                display: "flex",
                justifyContent: "space-between",
                alignItems: "center",
                fontSize: "0.8rem",
              }}
            >
              <span style={{ color: "var(--amber)" }}>
                {pendingConclusionDeletions} pending conclusion deletion
                {pendingConclusionDeletions > 1 ? " requests" : " request"}
              </span>
              <span
                className="mono"
                style={{
                  fontSize: "0.6rem",
                  color: "var(--amber-dim)",
                  textTransform: "uppercase",
                }}
              >
                Review →
              </span>
            </div>
          </Link>
        )}

        {(failedUploads > 0 || pendingUploads > 0) && (
          <Link href="/library" style={{ textDecoration: "none", display: "block" }}>
            <div
              className="portal-card"
              style={{
                padding: "0.7rem 1rem",
                marginBottom: "1rem",
                display: "flex",
                justifyContent: "space-between",
                alignItems: "center",
                fontSize: "0.8rem",
              }}
            >
              <span style={{ color: "var(--parchment-dim)" }}>
                {failedUploads > 0 && (
                  <span style={{ color: "var(--ember)" }}>
                    {failedUploads} failed upload{failedUploads > 1 ? "s" : ""}
                  </span>
                )}
                {failedUploads > 0 && pendingUploads > 0 && " · "}
                {pendingUploads > 0 && (
                  <span>{pendingUploads} processing</span>
                )}
              </span>
              <span
                className="mono"
                style={{
                  fontSize: "0.6rem",
                  color: "var(--amber-dim)",
                  textTransform: "uppercase",
                }}
              >
                View in library →
              </span>
            </div>
          </Link>
        )}

        {pendingRequestCount > 0 ? (
          <Link
            href="/library#requests"
            style={{ textDecoration: "none", display: "block" }}
          >
            <div
              className="portal-card"
              style={{
                border: "1px solid var(--amber)",
                background:
                  "linear-gradient(180deg, rgba(212,160,23,0.10), rgba(212,160,23,0.03))",
                padding: "0.9rem 1.1rem",
                marginBottom: "1.5rem",
                display: "flex",
                justifyContent: "space-between",
                alignItems: "center",
                gap: "1rem",
                transition: "border-color 0.2s ease",
              }}
            >
              <span
                className="mono"
                style={{
                  color: "var(--amber)",
                  fontSize: "0.62rem",
                  letterSpacing: "0.28em",
                  textTransform: "uppercase",
                }}
              >
                ⚠ {pendingRequestCount} deletion request
                {pendingRequestCount === 1 ? "" : "s"} awaiting your decision
              </span>
              <span
                className="mono"
                style={{
                  color: "var(--amber-dim)",
                  fontSize: "0.6rem",
                  letterSpacing: "0.22em",
                  textTransform: "uppercase",
                }}
              >
                Review →
              </span>
            </div>
          </Link>
        ) : null}

        <div
          style={{
            display: "flex",
            justifyContent: "flex-end",
            alignItems: "center",
            marginBottom: "1.25rem",
            gap: "0.75rem",
          }}
        >
          <Link href="/library" className="btn">
            Library
          </Link>
          <Link href="/upload" className="btn-solid btn">
            Upload
          </Link>
        </div>

        <div
          style={{
            display: "grid",
            gridTemplateColumns: "1fr 1fr",
            gap: "1.5rem",
          }}
        >
          <section
            className="ascii-frame"
            data-label={`UPLOADS · ${toRoman(ingestedUploads.length) || "0"}`}
          >
            <div style={{ display: "flex", flexDirection: "column", gap: "0.5rem" }}>
              {ingestedUploads.length === 0 ? (
                <LatinEmpty
                  latin="Scriba exspectat."
                  english="The scribe awaits — nothing ingested yet."
                />
              ) : (
                ingestedUploads.map((u) => (
                  <div key={u.id} className="portal-card" style={{ padding: "0.9rem 1rem" }}>
                    <div
                      style={{
                        display: "flex",
                        justifyContent: "space-between",
                        gap: "1rem",
                        alignItems: "flex-start",
                      }}
                    >
                      <div style={{ minWidth: 0 }}>
                        <div
                          style={{
                            display: "flex",
                            alignItems: "center",
                            gap: "0.45rem",
                            overflow: "hidden",
                          }}
                        >
                          <span
                            style={{
                              fontFamily: "'EB Garamond', serif",
                              color: "var(--parchment)",
                              overflow: "hidden",
                              textOverflow: "ellipsis",
                              whiteSpace: "nowrap",
                            }}
                          >
                            {u.title}
                          </span>
                          {u.visibility === "private" ? (
                            <span
                              className="mono"
                              title="Private — only you see this row. Noosphere still analyses it."
                              style={{
                                fontSize: "0.5rem",
                                letterSpacing: "0.22em",
                                textTransform: "uppercase",
                                color: "var(--amber)",
                                border: "1px solid var(--amber-dim)",
                                padding: "0.08rem 0.38rem",
                                borderRadius: "2px",
                                flexShrink: 0,
                              }}
                            >
                              Private
                            </span>
                          ) : u.visibility === "semi-private" ? (
                            // Matches the /library badge — semi-private
                            // uploads are firm-readable but blocked
                            // from the public blog. Same visual weight
                            // as Private so the constraint is obvious
                            // at a glance.
                            <span
                              className="mono"
                              title="Semi-private — firm sees this; public blog never does. Noosphere still analyses it."
                              style={{
                                fontSize: "0.5rem",
                                letterSpacing: "0.22em",
                                textTransform: "uppercase",
                                color: "var(--amber)",
                                border: "1px solid var(--amber-dim)",
                                padding: "0.08rem 0.38rem",
                                borderRadius: "2px",
                                flexShrink: 0,
                              }}
                            >
                              Semi-private
                            </span>
                          ) : null}
                        </div>
                        <div
                          className="mono"
                          style={{
                            fontSize: "0.65rem",
                            color: "var(--parchment-dim)",
                            marginTop: "0.25rem",
                          }}
                        >
                          {u.founder.name} · {new Date(u.createdAt).toLocaleDateString()}
                        </div>
                      </div>
                      <div
                        style={{
                          display: "flex",
                          gap: "0.5rem",
                          alignItems: "center",
                          flexShrink: 0,
                          flexWrap: "wrap",
                          justifyContent: "flex-end",
                        }}
                      >
                        <PublishToggle
                          uploadId={u.id}
                          initialPublishedAt={u.publishedAt}
                          initialSlug={u.slug}
                        />
                      </div>
                    </div>
                  </div>
                ))
              )}
            </div>
          </section>

          <section
            className="ascii-frame"
            data-label={`CONCLUSIONS · ${toRoman(conclusions.length) || "0"}`}
          >
            <div style={{ display: "flex", flexDirection: "column", gap: "0.5rem" }}>
              {conclusions.length === 0 ? (
                <LatinEmpty
                  latin="Adhuc nihil firmandum."
                  english="Nothing yet for the firm to affirm."
                />
              ) : (
                conclusions.map((c) => (
                  <div key={c.id} className="portal-card" style={{ padding: "0.9rem 1rem" }}>
                    <div
                      style={{
                        display: "flex",
                        gap: "0.9rem",
                        alignItems: "flex-start",
                      }}
                    >
                      <ConfidenceTierSigil tier={c.confidenceTier} />
                      <div style={{ minWidth: 0, flex: 1 }}>
                        <div
                          className="mono"
                          style={{
                            fontSize: "0.6rem",
                            color: "var(--amber-dim)",
                            textTransform: "uppercase",
                            letterSpacing: "0.12em",
                          }}
                        >
                          {c.confidenceTier} · {c.topicHint || "general"}
                        </div>
                        <p
                          style={{
                            marginTop: "0.4rem",
                            marginBottom: 0,
                            fontSize: "0.95rem",
                            color: "var(--parchment)",
                            lineHeight: 1.5,
                          }}
                        >
                          {c.text}
                        </p>
                      </div>
                      <form action={dismissConclusion}>
                        <input type="hidden" name="conclusionId" value={c.id} />
                        <button
                          type="submit"
                          title="Dismiss from dashboard"
                          style={{
                            background: "none",
                            border: "none",
                            color: "var(--parchment-dim)",
                            cursor: "pointer",
                            fontSize: "0.9rem",
                            padding: "0.1rem 0.4rem",
                            opacity: 0.6,
                            lineHeight: 1,
                          }}
                        >
                          ×
                        </button>
                      </form>
                    </div>
                  </div>
                ))
              )}
            </div>
          </section>
        </div>

        <div className="meander" aria-hidden="true" />

        <section
          className="ascii-frame"
          data-label={`DRIFT EVENTS · ${toRoman(drifts.length) || "0"}`}
          style={{ marginTop: "0.5rem" }}
        >
          {drifts.length === 0 ? (
            <LatinEmpty
              latin="Fundamenta firma."
              english="No drift observed — the foundations are firm."
            />
          ) : (
            <div style={{ display: "flex", flexDirection: "column", gap: "0.5rem" }}>
              {drifts.map((d) => (
                <div key={d.id} className="portal-card" style={{ padding: "0.9rem 1rem" }}>
                  <div className="mono" style={{ fontSize: "0.72rem", color: "var(--ember)" }}>
                    score {(d.driftScore * 100).toFixed(0)}% · {d.targetKind}{" "}
                    {d.targetId.slice(0, 8)}…
                  </div>
                  <p
                    style={{
                      marginTop: "0.35rem",
                      fontSize: "0.9rem",
                      color: "var(--parchment-dim)",
                      lineHeight: 1.5,
                    }}
                  >
                    {d.naturalLanguageSummary || d.notes || "—"}
                  </p>
                  <div
                    className="mono"
                    style={{
                      fontSize: "0.6rem",
                      color: "var(--parchment-dim)",
                      marginTop: "0.3rem",
                    }}
                  >
                    {new Date(d.observedAt).toLocaleDateString()}
                  </div>
                </div>
              ))}
            </div>
          )}
        </section>
      </main>
    </div>
  );
}

/** Inline Latin empty state for populated `ascii-frame` sections. */
function LatinEmpty({ latin, english }: { latin: string; english: string }) {
  return (
    <div style={{ padding: "1rem 0.25rem", textAlign: "center" }}>
      <p
        style={{
          fontFamily: "'EB Garamond', serif",
          fontStyle: "italic",
          fontSize: "1rem",
          color: "var(--parchment)",
          margin: 0,
        }}
      >
        {latin}
      </p>
      <p
        className="mono"
        style={{
          fontSize: "0.7rem",
          color: "var(--parchment-dim)",
          marginTop: "0.25rem",
        }}
      >
        {english}
      </p>
    </div>
  );
}

/** Small positive int → Roman numerals, for display accents only. */
function toRoman(n: number): string {
  if (!n || n < 1) return "";
  const table: [number, string][] = [
    [10, "X"],
    [9, "IX"],
    [5, "V"],
    [4, "IV"],
    [1, "I"],
  ];
  let out = "";
  let rem = n;
  for (const [v, s] of table) {
    while (rem >= v) {
      out += s;
      rem -= v;
    }
  }
  return out;
}

